mapper.select:
SELECT id , name,code FROM ct_srm_user where is_valid=1
and person_type=#{userDto.personType}
and (name LIKE CONCAT('%', #{userDto.name}, '%') or account LIKE CONCAT('%', #{userDto.name}, '%') or alias LIKE CONCAT('%', #{userDto.name}, '%'))

select su.id as rowId,su.code as code,su.name as name,pt.code as "personType.id",pt.name as "personType.name",pt.code as personTypeCode,pt.name as personTypeName, pt.is_external as is_external,pt.is_graduate,id_num as idNum,title, phone, email,edu_degree,bank_name as bankName, bank_account as bankAccount, stt.code as titleCode,stt.name as titleName,sed.code as eduDegreeCode,sed.name as eduDegreeName, stt.code as "title.id",stt.name as "title.name",sed.code as "eduDegree.id",sed.name as "eduDegree.name",account, csd.id as "dept.id",csd.name as "dept.name",csd.name as deptName,su.account as account,su.bank_account as bankAccount, pt.is_external, case when pt.is_external=0 then '1' else '0' END as isOurHosp, su.sex as sex, case when su.sex=0 then '女' when su.sex=1 then '男' else '' END as sexName, su.duty, case when pt.is_external=1 then 'ExternalUser' when pt.is_graduate=1 then 'GradUser' else 'User' END as personTypeAlias,su.is_teacher as isTeacher, su.update_time as auditDate, (select name from ct_srm_user WHERE id=su.update_user) as auditUserName, case when su.check_status=1 then '通过' when su.check_status=2 then '不通过' else '' end as checkStatus from ct_srm_user su left join ct_srm_person_type pt on su.person_type=pt.code left join ct_srm_title_info stt on su.title=stt.code left join ct_srm_edu_degree sed on su.edu_degree=sed.code left join ct_srm_dept_user sdu on su.id=sdu.user left join ct_srm_dept csd on csd.id=su.dept left join ct_srm_occupation_category csoc on csoc.code=su.occupation_category left join ct_srm_edu_level csel on csel.code=su.edu_level left join ct_srm_job_type csjt on csjt.code=su.job_type left join ct_srm_job_level csjl on csjl.code=su.job_level left join ct_srm_parttime_job cspj on cspj.code=su.parttime left join ct_srm_teacher_type csty on csty.code=su.teacher_type left join ct_srm_polity csp on csp.code=su.polity left join ct_srm_nationality csnc on csnc.code=su.nationlity left join ct_srm_nation csnm on csnm.code=su.nation where 1=1
and su.code=#{code}
and su.id=#{id}

select su.id as rowId,su.code as code,su.name as name, case when su.sex=0 then '女' when su.sex=1 then '男' else '' END as sexName, pt.name as personTypeName, csoc.name as occupationCategoryName, stt.name as titleName, csel.name as eduLevelName, su.duty_date as dutyDate, sdept.name as deptName, sed.name as eduDegreeName, su.account as account,su.is_expert as isExpert,su.is_ethical_expert as isEthicalExpert, su.direction as direction,su.is_stat as isStat,su.is_valid as isValid,su.introduction as introduction, su.id_num as idNum,su.birthday as birthday,su.email as email, csjl.name as jobLevelName, csjt.name as jobTypeName, fdiscipline.name as disciplineOneName, sdiscipline.name as disciplineTwoName, tdiscipline.name as disciplineThreeName, cspj.name as parttimePosName, su.graduate_school as graduateSchool,su.start_date as startDate,su.end_date as endDate, su.profess as profess,csty.name as teacherTypeName, su.employ_date as employDate,su.duty as duty, csnc.name as nationlityName, csnm.name as nationName, su.postcode as postcode,su.portraiture as portraiture,su.mobile as mobile,su.learning as learning,su.experience_abroad as experienceAbroad, case when pt.is_external=1 then 'ExternalUser' when pt.is_graduate=1 then 'GradUser' else 'User' END as personTypeAlias ,su.person_state as personState,csps.name as personStateName ,su.class_code as classCode,sclass.name as classCodeName ,su.phone ,su.is_teacher as isTeacher from ct_srm_user su left join ct_srm_person_type pt on su.person_type=pt.code left join ct_srm_title_info stt on su.title=stt.code left join ct_srm_edu_degree sed on su.edu_degree=sed.code left join ct_srm_dept_user sdu on su.id=sdu.user left join ct_srm_occupation_category csoc on csoc.code=su.occupation_category left join ct_srm_edu_level csel on csel.code=su.edu_level left join ct_srm_job_type csjt on csjt.code=su.job_type left join ct_srm_job_level csjl on csjl.code=su.job_level left join ct_srm_parttime_job cspj on cspj.code=su.parttime_pos left join ct_srm_teacher_type csty on csty.code=su.teacher_type left join ct_srm_polity csp on csp.code=su.polity left join ct_srm_nationality csnc on csnc.code=su.nationlity left join ct_srm_nation csnm on csnm.code=su.nation left join ct_srm_class sclass on sclass.code=su.class_code left join ct_srm_discipline fdiscipline on fdiscipline.code=su.discipline_one left join ct_srm_discipline sdiscipline on sdiscipline.code=su.discipline_two left join ct_srm_discipline tdiscipline on tdiscipline.code=su.discipline_three left join ct_srm_dept sdept on sdept.id=su.dept left join ct_srm_person_state csps on su.person_state=csps.code where 1=1
and pt.is_external=#{userDto.isOut}
and pt.is_graduate=#{userDto.isGraduate}
and pt.is_instaff=#{userDto.isInStaff}
and su.check_status=#{userDto.auditState}
and su.account like concat('%',#{userDto.account},'%')
and su.code like concat('%',#{userDto.code},'%')
and su.name like concat('%',#{userDto.name},'%')
and su.dept =#{userDto.dept}
and su.edu_level =#{userDto.eduLevel}
and su.edu_degree =#{userDto.eduDegree}
and su.occupation_category =#{userDto.occupationCategory}
and su.job_type =#{userDto.jobType}
and su.is_expert =#{userDto.isExpert}
and su.is_ethical_expert =#{userDto.isEthicalExpert}
and su.check_status=#{userDto.auditState}

select su.id as rowId,su.code as code,su.name as name, case when su.sex=0 then '女' when su.sex=1 then '男' else '' END as sexName, pt.name as personTypeName, csoc.name as occupationCategoryName, stt.name as titleName, csel.name as eduLevelName, su.duty_date as dutyDate, sdept.name as deptName, sed.name as eduDegreeName, su.account as account,su.is_expert as isExpert,su.is_ethical_expert as isEthicalExpert, su.direction as direction,su.is_stat as isStat,su.is_valid as isValid,su.introduction as introduction, su.id_num as idNum,su.birthday as birthday,su.email as email, csjl.name as jobLevelName, csjt.name as jobTypeName, fdiscipline.name as disciplineOneName, sdiscipline.name as disciplineTwoName, tdiscipline.name as disciplineThreeName, cspj.name as parttimePosName, su.graduate_school as graduateSchool,su.start_date as startDate,su.end_date as endDate, su.profess as profess,csty.name as teacherTypeName, su.employ_date as employDate,su.duty as duty, csnc.name as nationlityName, csnm.name as nationName, su.postcode as postcode,su.portraiture as portraiture,su.mobile as mobile,su.learning as learning,su.experience_abroad as experienceAbroad, case when pt.is_external=1 then 'ExternalUser' when pt.is_graduate=1 then 'GradUser' else 'User' END as personTypeAlias ,su.phone,su.is_teacher as isTeacher from ct_srm_user su left join ct_srm_person_type pt on su.person_type=pt.code left join ct_srm_title_info stt on su.title=stt.code left join ct_srm_edu_degree sed on su.edu_degree=sed.code left join ct_srm_dept_user sdu on su.id=sdu.user left join ct_srm_occupation_category csoc on csoc.code=su.occupation_category left join ct_srm_edu_level csel on csel.code=su.edu_level left join ct_srm_job_type csjt on csjt.code=su.job_type left join ct_srm_job_level csjl on csjl.code=su.job_level left join ct_srm_parttime_job cspj on cspj.code=su.parttime_pos left join ct_srm_teacher_type csty on csty.code=su.teacher_type left join ct_srm_polity csp on csp.code=su.polity left join ct_srm_nationality csnc on csnc.code=su.nationlity left join ct_srm_nation csnm on csnm.code=su.nation left join ct_srm_class sclass on sclass.code=su.class_code left join ct_srm_discipline fdiscipline on fdiscipline.code=su.discipline_one left join ct_srm_discipline sdiscipline on sdiscipline.code=su.discipline_two left join ct_srm_discipline tdiscipline on tdiscipline.code=su.discipline_three left join ct_srm_dept sdept on sdept.id=su.dept where su.is_valid=1
and pt.is_external=#{userDto.isOut}
and pt.is_graduate=#{userDto.isGraduate}
and su.account like concat('%',#{userDto.account},'%')
and su.code like concat('%',#{userDto.code},'%')
and su.name like concat('%',#{userDto.name},'%')
and su.dept =#{userDto.dept}
and su.edu_level =#{userDto.eduLevel}
and su.edu_degree =#{userDto.eduDegree}
and su.honor_title =#{userDto.honorTitle}
and su.job_type =#{userDto.jobType}
and su.check_status=#{userDto.auditState}
and su.person_type=#{userDto.personType}

select su.id as rowId,su.code as code,su.name as name, case when su.sex=0 then '女' when su.sex=1 then '男' else '' END as sexName, pt.name as personTypeName, csoc.name as occupationCategoryName, stt.name as titleName, csel.name as eduLevelName, su.duty_date as dutyDate, sdept.name as deptName, sed.name as eduDegreeName, su.account as account,su.is_expert as isExpert,su.is_ethical_expert as isEthicalExpert, su.direction as direction,su.is_stat as isStat,su.is_valid as isValid,su.introduction as introduction, su.id_num as idNum,su.birthday as birthday,su.email as email, csjl.name as jobLevelName, csjt.name as jobTypeName, fdiscipline.name as disciplineOneName, sdiscipline.name as disciplineTwoName, tdiscipline.name as disciplineThreeName, cspj.name as parttimePosName, su.graduate_school as graduateSchool,su.start_date as startDate,su.end_date as endDate, su.profess as profess,csty.name as teacherTypeName, su.employ_date as employDate,su.duty as duty, csnc.name as nationlityName, csnm.name as nationName, su.postcode as postcode,su.portraiture as portraiture,su.mobile as mobile,su.learning as learning,su.experience_abroad as experienceAbroad, case when pt.is_external=1 then 'ExternalUser' when pt.is_graduate=1 then 'GradUser' else 'User' END as personTypeAlias ,su.phone,su.is_teacher as isTeacher from ct_srm_user su left join ct_srm_person_type pt on su.person_type=pt.code left join ct_srm_title_info stt on su.title=stt.code left join ct_srm_edu_degree sed on su.edu_degree=sed.code left join ct_srm_dept_user sdu on su.id=sdu.user left join ct_srm_occupation_category csoc on csoc.code=su.occupation_category left join ct_srm_edu_level csel on csel.code=su.edu_level left join ct_srm_job_type csjt on csjt.code=su.job_type left join ct_srm_job_level csjl on csjl.code=su.job_level left join ct_srm_parttime_job cspj on cspj.code=su.parttime_pos left join ct_srm_teacher_type csty on csty.code=su.teacher_type left join ct_srm_polity csp on csp.code=su.polity left join ct_srm_nationality csnc on csnc.code=su.nationlity left join ct_srm_nation csnm on csnm.code=su.nation left join ct_srm_class sclass on sclass.code=su.class_code left join ct_srm_discipline fdiscipline on fdiscipline.code=su.discipline_one left join ct_srm_discipline sdiscipline on sdiscipline.code=su.discipline_two left join ct_srm_discipline tdiscipline on tdiscipline.code=su.discipline_three left join ct_srm_dept sdept on sdept.id=su.dept where su.is_expert =1
and su.code like concat('%',#{userExpertQueryDto.paUserCode},'%')
and su.name like concat('%',#{userExpertQueryDto.paUserName},'%')
and su.person_type=#{userExpertQueryDto.paUserType}
and su.sex=#{userExpertQueryDto.paUserSex}
and su.edu_degree=#{userExpertQueryDto.paUserDegree}
and su.edu_level=#{userExpertQueryDto.paUserEduLevel}
and su.title=#{userExpertQueryDto.paUserTitle}
and su.direction like concat('%',#{userExpertQueryDto.paUserDirection},'%')
and su.occupation_category=#{userExpertQueryDto.paOccuCategory}
and su.dept =#{userExpertQueryDto.paDept}
and su.honor_title =#{userExpertQueryDto.paHonorTitle}
and su.job_type =#{userExpertQueryDto.paJobType}
and su.parttime_pos =#{userExpertQueryDto.paPartTimePos}

select su.id as rowId,su.code as code,su.name as name, case when su.sex=0 then '女' when su.sex=1 then '男' else '' END as sexName, pt.name as personTypeName, csoc.name as occupationCategoryName, stt.name as titleName, csel.name as eduLevelName, su.duty_date as dutyDate, sdept.name as deptName, sed.name as eduDegreeName, su.account as account,su.is_expert as isExpert,su.is_ethical_expert as isEthicalExpert, su.direction as direction,su.is_stat as isStat,su.is_valid as isValid,su.introduction as introduction, su.id_num as idNum,su.birthday as birthday,su.email as email, csjl.name as jobLevelName, csjt.name as jobTypeName, fdiscipline.name as disciplineOneName, sdiscipline.name as disciplineTwoName, tdiscipline.name as disciplineThreeName, cspj.name as parttimePosName, su.graduate_school as graduateSchool,su.start_date as startDate,su.end_date as endDate, su.profess as profess,csty.name as teacherTypeName, su.employ_date as employDate,su.duty as duty, csnc.name as nationlityName, csnm.name as nationName, su.postcode as postcode,su.portraiture as portraiture,su.mobile as mobile,su.learning as learning,su.experience_abroad as experienceAbroad, case when pt.is_external=1 then 'ExternalUser' when pt.is_graduate=1 then 'GradUser' else 'User' END as personTypeAlias ,su.phone,su.is_teacher as isTeacher from ct_srm_user su left join ct_srm_person_type pt on su.person_type=pt.code left join ct_srm_title_info stt on su.title=stt.code left join ct_srm_edu_degree sed on su.edu_degree=sed.code left join ct_srm_dept_user sdu on su.id=sdu.user left join ct_srm_occupation_category csoc on csoc.code=su.occupation_category left join ct_srm_edu_level csel on csel.code=su.edu_level left join ct_srm_job_type csjt on csjt.code=su.job_type left join ct_srm_job_level csjl on csjl.code=su.job_level left join ct_srm_parttime_job cspj on cspj.code=su.parttime_pos left join ct_srm_teacher_type csty on csty.code=su.teacher_type left join ct_srm_polity csp on csp.code=su.polity left join ct_srm_nationality csnc on csnc.code=su.nationlity left join ct_srm_nation csnm on csnm.code=su.nation left join ct_srm_class sclass on sclass.code=su.class_code left join ct_srm_discipline fdiscipline on fdiscipline.code=su.discipline_one left join ct_srm_discipline sdiscipline on sdiscipline.code=su.discipline_two left join ct_srm_discipline tdiscipline on tdiscipline.code=su.discipline_three left join ct_srm_dept sdept on sdept.id=su.dept where su.is_valid =1
